```class Solution {
public:
    bool equalFrequency(string word) {
        unordered_map<char, int> charFrequency;
        for (char c : word) {
            charFrequency[c]++;
        }
        int minDiff = INT_MAX;
        int index = -1;
        for (int i = 0; i < word.length(); i++) {
            int currDiff = charFrequency[word[i]] - charFrequency['a'];
            if (currDiff < minDiff) {
                minDiff = currDiff;
                index = i;
            }
        }
        return index != -1;
    }
};
```

